305	// TestLand_MergeConflict verifies that a merge conflict is handled cleanly:
306	// the target branch is untouched, the original ResultRev is preserved under
307	// refs/ddx/iterations/, and no stale worktree is left behind.
308	func TestLand_MergeConflict(t *testing.T) {
309		r := newLandTestRepo(t)
310		ops := RealLandingGitOps{}
311	
312		// Worker edits feature.txt starting from baseSHA.
313		workerSHA := r.commitOn(r.baseSHA, "feature.txt", "worker-version\n", "feat: worker")
314	
315		// Sibling edits the SAME file (feature.txt) on main. Merging the worker
316		// commit into this tip will conflict.
317		siblingSHA := r.commitOn(r.baseSHA, "feature.txt", "sibling-version\n", "feat: sibling")
318		r.runGit("update-ref", "refs/heads/main", siblingSHA)
319	
320		req := LandRequest{
321			WorktreeDir:  r.dir,
322			BaseRev:      r.baseSHA,
323			ResultRev:    workerSHA,
324			BeadID:       "ddx-land-conflict",
325			AttemptID:    "20260414T000002-eeff",
326			TargetBranch: "main",
327		}
328		land, err := Land(r.dir, req, ops)
329		if err != nil {
330			t.Fatalf("Land: %v", err)
331		}
332		if land.Status != "preserved" {
333			t.Fatalf("expected status=preserved on conflict, got %q", land.Status)
334		}
335		if land.PreserveRef == "" || !strings.HasPrefix(land.PreserveRef, "refs/ddx/iterations/ddx-land-conflict/") {
336			t.Errorf("expected preserve ref under refs/ddx/iterations/ddx-land-conflict/, got %q", land.PreserveRef)
337		}
338		if land.Reason == "" {
339			t.Errorf("expected non-empty Reason on preserve, got empty")
340		}
341		// Target branch must be unchanged from the sibling commit.
342		if got := r.resolveRef("refs/heads/main"); got != siblingSHA {
343			t.Errorf("main tip = %s, want %s (unchanged)", got, siblingSHA)
344		}
345		// Preserve ref must exist and resolve to the original worker SHA.
346		if got := r.resolveRef(land.PreserveRef); got != workerSHA {
347			t.Errorf("preserve ref resolves to %s, want %s", got, workerSHA)
348		}
349		// No stale ddx-land-wt-* worktrees (the merge ran in a temp worktree
350		// which must have been cleaned up on abort).
351		wtList := r.runGit("worktree", "list", "--porcelain")
352		for _, line := range strings.Split(wtList, "\n") {
353			if strings.HasPrefix(line, "worktree ") && strings.Contains(line, "ddx-land-wt-") {
354				t.Errorf("stale land worktree left behind: %q", line)
355			}
356		}
357	}
