334		// the field; merge conflict or gate failure overrides the worker-level
335		// classification; other preserved outcomes keep the worker's mode.
336		res.FailureMode = classifyLandingFailureMode(landing.Outcome, landing.Reason, landing.GateResults, res.FailureMode)
